                            '</span>'
                            f'<div class="body"><span class="name">{_h(name)}</span>'
                            f'<span class="meta">{n_swims} swim{"" if n_swims == 1 else "s"} · '
                            f'<time class="mh-rel" datetime="{_h(when_iso)}">{_h(when)}</time></span>'
                            '</div>'
